/**
 * Parse Mistral Response — extrait la réponse + les tokens consommés
 */
const mistralOutput = $input.first().json;
const choice = mistralOutput.choices?.[0];
const usage = mistralOutput.usage || {};

let parsed;
try {
  const text = choice?.message?.content || '{}';
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    response_text: choice?.message?.content || 'Désolé, je n\'ai pas compris. Pouvez-vous reformuler ?',
    action: 'none',
    booking_data: {}
  };
}

return [{
  json: {
    ...$('Compute Budget Status').first().json,
    response_text: parsed.response_text,
    action: parsed.action || 'none',
    booking_data: parsed.booking_data || {},
    // Token tracking
    llm_provider: 'mistral',
    llm_model: 'mistral-small-latest',
    llm_prompt_tokens: usage.prompt_tokens || 0,
    llm_completion_tokens: usage.completion_tokens || 0,
    llm_total_tokens: usage.total_tokens || 0,
    llm_is_fallback: true,
    llm_error: null
  }
}];

/**
 * Static Fallback — message prédéfini quand les 2 LLMs sont down ou budget épuisé
 */
const context = $('Compute Budget Status').first().json;
const budgetExceeded = context.ai_budget_exceeded;

let message;
if (budgetExceeded) {
  message = 'Bonjour ! Notre assistant est temporairement indisponible. ' +
    'Veuillez nous contacter directement par téléphone pour prendre rendez-vous. ' +
    'Nous nous excusons pour la gêne occasionnée.';
} else {
  message = 'Bonjour ! Notre assistant rencontre un problème technique. ' +
    'Un conseiller vous recontactera dans les plus brefs délais. ' +
    'Nous nous excusons pour la gêne occasionnée.';
}

return [{
  json: {
    ...context,
    response_text: message,
    action: 'none',
    booking_data: {},
    // Token tracking
    llm_provider: 'static',
    llm_model: 'static-fallback',
    llm_prompt_tokens: 0,
    llm_completion_tokens: 0,
    llm_total_tokens: 0,
    llm_is_fallback: true,
    llm_error: budgetExceeded ? 'budget_exceeded' : 'both_llms_down'
  }
}];

/**
 * Build Context — flatten webhook + merchant + client into a single object
 * for downstream nodes (Sanitize, Check Budget, AI prompt, etc.)
 */
const wh = $('Webhook Trigger').first().json;
const body = wh.body || wh;

const merchantArr = $('Find Merchant').first().json;
const merchant = (Array.isArray(merchantArr) && merchantArr.length > 0) ? merchantArr[0] : (merchantArr || {});

const clientResp = $('Identify Client').first().json;
const client = Array.isArray(clientResp) && clientResp.length > 0
  ? clientResp[0]
  : (clientResp && clientResp.id ? clientResp : {});

return [{
  json: {
    // From Webhook payload
    channel: body.channel || 'whatsapp',
    sender_id: body.sender_phone || body.sender_id,
    sender_name: body.sender_name,
    message_text: body.message_text || '',
    wa_message_id: body.wa_message_id,
    wa_phone_number_id: body.wa_phone_number_id,
    timestamp: body.timestamp,

    // From Find Merchant
    merchant_id: merchant.id,
    salon_name: merchant.name || 'Salon',
    ai_name: merchant.ai_name || 'AurA',
    ai_tone: merchant.ai_tone || 'friendly',
    ai_languages: merchant.ai_languages || ['fr'],
    preferred_language: (merchant.ai_languages && merchant.ai_languages[0]) || 'fr',
    cancellation_delay_minutes: merchant.cancellation_delay_minutes || 120,
    opening_hours: merchant.opening_hours || {},
    ai_monthly_token_budget: merchant.ai_monthly_token_budget || 100000,
    ai_alert_email: merchant.ai_alert_email || null,

    // From Identify Client (upsert result)
    client_id: client.id,
    client_name: client.name || body.sender_name || 'Inconnu',
    loyalty_points: client.loyalty_points || 0,
    preferred_service: client.preferred_service_id || 'aucun',
    preferred_practitioner: client.preferred_practitioner_id || 'aucun',

    // Placeholders (filled by downstream nodes)
    conversation_id: null,
    conversation_history: 'Premiere interaction',
    available_slots_text: 'Aucun creneau charge'
  }
}];

/**
 * Compute Budget Status — agrège merchant budget + usage du mois
 */
const sanitized = $('Sanitize Prompt Inputs').first().json;

const merchantData = $('Get Merchant Budget').first().json;
const merchant = (Array.isArray(merchantData) && merchantData.length > 0) ? merchantData[0] : {};

const usageData = $('Get Monthly Token Usage').first().json;
const usageRows = Array.isArray(usageData) ? usageData : [];

const budget = merchant.ai_monthly_token_budget || 100000;
const alertEmail = merchant.ai_alert_email || null;
const totalUsed = usageRows.reduce((sum, r) => sum + (r.total_tokens || 0), 0);
const usagePercent = budget > 0 ? Math.round((totalUsed / budget) * 100) : 0;
const budgetExceeded = totalUsed >= budget;

return [{
  json: {
    ...sanitized,
    ai_budget: budget,
    ai_alert_email: alertEmail,
    ai_used_tokens: totalUsed,
    ai_usage_percent: usagePercent,
    ai_budget_exceeded: budgetExceeded
  }
}];

/**
 * Compute Token Cost — calcule cost_eur depuis les tokens LLM
 */
const data = $input.first().json;

const PRICING = {
  gemini: { prompt: 0.075 / 1_000_000, completion: 0.30 / 1_000_000 },
  mistral: { prompt: 0.10 / 1_000_000, completion: 0.30 / 1_000_000 },
  static: { prompt: 0, completion: 0 }
};

const pricing = PRICING[data.llm_provider] || PRICING.static;
const costEur = (data.llm_prompt_tokens || 0) * pricing.prompt
              + (data.llm_completion_tokens || 0) * pricing.completion;

return [{
  json: {
    ...data,
    token_cost_eur: costEur
  }
}];

/**
 * Compute Alert Level — détermine le niveau d'alerte basé sur le budget
 * (anomaly detection 7j déférée — à ajouter via 2 HTTP nodes Get Daily Avg / Get Today)
 */
const data = $input.first().json;

const usedBefore = data.ai_used_tokens || 0;
const justAdded = data.llm_total_tokens || 0;
const newTotal = usedBefore + justAdded;
const budget = data.ai_budget || 100000;
const newPercent = budget > 0 ? Math.round((newTotal / budget) * 100) : 0;

let alertLevel = 'none';
if (newPercent >= 100) alertLevel = 'critical';
else if (newPercent >= 95) alertLevel = 'warning';
else if (newPercent >= 80) alertLevel = 'info';

return [{
  json: {
    ...data,
    token_log_cost_eur: data.token_cost_eur || 0,
    token_log_new_total: newTotal,
    token_log_new_percent: newPercent,
    token_log_alert_level: alertLevel,
    token_log_is_anomaly: false,
    token_log_daily_avg: 0
  }
}];

/**
 * Build Tool Response — formate les slots retournés par Check Availability en objet
 * response utilisable par Gemini (2e appel) dans le functionResponse part.
 *
 * Option D : Gemini function calling pattern.
 */
const availItems = $('Check Availability').all() || [];
const validSlots = availItems.filter(it => it && it.json && it.json.slot_start);

let tool_response_data;
if (validSlots.length === 0) {
  tool_response_data = {
    slots: [],
    count: 0,
    message: "Aucun créneau disponible pour cette date."
  };
} else {
  const timeFmt = new Intl.DateTimeFormat('fr-FR', {
    timeZone: 'Europe/Paris',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });
  const formatted = validSlots.map(it => ({
    time: timeFmt.format(new Date(it.json.slot_start)),
    iso: it.json.slot_start,
    practitioner: it.json.practitioner_name,
    practitioner_id: it.json.practitioner_id
  }));
  tool_response_data = {
    slots: formatted,
    count: formatted.length
  };
}

const ctx = $('Parse Gemini Response').first().json;

return [{
  json: {
    ...ctx,
    tool_response_data: tool_response_data
  }
}];

